class RBM(nn.Module):
    """Restricted Boltzmann Machine with binary visible and hidden units."""
    def __init__(self, n_visible: int, n_hidden: int):
        super().__init__()
        self.W = nn.Parameter(torch.randn(n_visible, n_hidden) * 0.01)
        self.b = nn.Parameter(torch.zeros(n_visible))   # visible bias
        self.c = nn.Parameter(torch.zeros(n_hidden))    # hidden bias

    def free_energy(self, v: torch.Tensor) -> torch.Tensor:
        """
        F(v) = -b^T v - sum_j log(1 + exp(c_j + W[:,j]^T v)).
        Lower free energy = higher p(v).
        """
        wx_b = v @ self.W + self.c       # (B, H)
        hidden_term = torch.log1p(torch.exp(wx_b)).sum(-1)  # (B,)
        return -(v @ self.b) - hidden_term

    def prob_h_given_v(self, v: torch.Tensor) -> torch.Tensor:
        """p(h_j=1 | v) = sigma(c_j + W[:,j]^T v)"""
        return torch.sigmoid(v @ self.W + self.c)   # (B, H)

    def prob_v_given_h(self, h: torch.Tensor) -> torch.Tensor:
        """p(v_i=1 | h) = sigma(b_i + W[i,:]^T h)"""
        return torch.sigmoid(h @ self.W.T + self.b)  # (B, V)

    def sample_h(self, v: torch.Tensor) -> torch.Tensor:
        p_h = self.prob_h_given_v(v)
        return torch.bernoulli(p_h)

    def sample_v(self, h: torch.Tensor) -> torch.Tensor:
        p_v = self.prob_v_given_h(h)
        return torch.bernoulli(p_v)
